export interface Message {
  id: string;
  role: 'user' | 'model';
  content: string;
  timestamp: Date;
  sources?: { title: string; uri: string }[];
}

export interface ElectionMetric {
  name: string;
  value: number;
  change: number;
  type: 'percentage' | 'currency' | 'number';
}

export interface Politician {
  id: string;
  name: string;
  party: string;
  role: string;
  spendings: number;
  assets: number;
  location: string;
}

export interface PollingData {
  date: string;
  candidateA: number;
  candidateB: number;
  candidateC: number;
  undecided: number;
}

import { ElectionMetric, Politician, PollingData } from './types';

