import { GoogleGenAI } from "@google/genai";

const API_KEY = process.env.API_KEY || "";

export const sendMessageToGemini = async (message: string, history: { role: 'user' | 'model', content: string }[]) => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        ...history.map(h => ({ role: h.role, parts: [{ text: h.content }] })),
        { role: 'user', parts: [{ text: message }] }
      ],
      config: {
        systemInstruction: `Você é o "PoliAgent", um especialista em política brasileira, dados do governo e transparência pública focado nas eleições de 2026.
        Seu objetivo é fornecer informações precisas, baseadas em dados e imparciais. 
        Sempre que falar sobre gastos ou leis, mencione a importância da transparência.
        Você tem acesso à pesquisa do Google para dados em tempo real sobre candidatos, pesquisas e notícias.
        Responda sempre em Português do Brasil.`,
        tools: [{ googleSearch: {} }],
      },
    });

    const text = response.text || "Desculpe, não consegui processar sua solicitação.";
    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map(chunk => ({
        title: chunk.web?.title || 'Fonte externa',
        uri: chunk.web?.uri || '#'
      }))
      .filter((v, i, a) => a.findIndex(t => t.uri === v.uri) === i) || [];

    return { text, sources };
  } catch (error) {
    console.error("Gemini Error:", error);
    return { text: "Ocorreu um erro ao conectar com o servidor de IA. Verifique sua chave API.", sources: [] };
  }
};

import React from 'react';
import { LayoutDashboard, MessageSquare, BarChart3, Database, Menu, X } from 'lucide-react';

interface NavigationProps {
  activeTab: string;
  setActiveTab: (tab: string) => void;
}

const Navigation: React.FC<NavigationProps> = ({ activeTab, setActiveTab }) => {
  const [isOpen, setIsOpen] = React.useState(false);

  const menuItems = [
    { id: 'dashboard', label: 'Painel 2026', icon: LayoutDashboard },
    { id: 'chat', label: 'PoliAgent AI', icon: MessageSquare },
    { id: 'analytics', label: 'Análise de Gastos', icon: BarChart3 },
    { id: 'data', label: 'Base de Dados', icon: Database },
  ];

  return (
    <nav className="fixed top-0 left-0 w-full lg:w-64 h-auto lg:h-screen bg-white lg:bg-gray-900 border-r border-gray-200 lg:border-gray-800 z-50">
      <div className="flex items-center justify-between p-4 lg:p-8">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 bg-green-600 rounded-lg flex items-center justify-center text-white font-bold">P</div>
          <span className="text-xl font-bold tracking-tight lg:text-white">PoliData 2026</span>
        </div>
        <button onClick={() => setIsOpen(!isOpen)} className="lg:hidden p-2 text-gray-500">
          {isOpen ? <X size={24} /> : <Menu size={24} />}
        </button>
      </div>

      <div className={`${isOpen ? 'block' : 'hidden'} lg:block px-4 py-2`}>
        {menuItems.map((item) => (
          <button
            key={item.id}
            onClick={() => {
              setActiveTab(item.id);
              setIsOpen(false);
            }}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl mb-2 transition-all duration-200 ${
              activeTab === item.id
                ? 'bg-green-600 text-white shadow-lg shadow-green-900/20'
                : 'text-gray-400 hover:text-white hover:bg-gray-800'
            }`}
          >
            <item.icon size={20} />
            <span className="font-medium">{item.label}</span>
          </button>
        ))}
      </div>

      <div className="hidden lg:block absolute bottom-8 left-0 w-full px-8">
        <div className="p-4 bg-gray-800 rounded-2xl border border-gray-700">
          <p className="text-xs text-gray-400 mb-2 uppercase tracking-widest font-bold">Eleições em</p>
          <div className="text-xl font-bold text-white flex gap-1 items-baseline">
            <span>~2</span>
            <span className="text-xs text-gray-500 font-normal">anos restantes</span>
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navigation;

import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, Loader2, Search, ExternalLink } from 'lucide-react';
import { sendMessageToGemini } from '../services/geminiService';
import { Message } from '../types';

const Chat: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    {
      id: '1',
      role: 'model',
      content: 'Olá! Sou o PoliAgent. Posso te ajudar com dados de transparência, gastos públicos e cenários para as eleições de 2026. O que gostaria de saber hoje?',
      timestamp: new Date(),
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: input,
      timestamp: new Date(),
    };

    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    const history = messages.map(m => ({ role: m.role, content: m.content }));
    const response = await sendMessageToGemini(input, history);

    const aiMessage: Message = {
      id: (Date.now() + 1).toString(),
      role: 'model',
      content: response.text,
      timestamp: new Date(),
      sources: response.sources
    };

    setMessages(prev => [...prev, aiMessage]);
    setIsLoading(false);
  };

  return (
    <div className="flex flex-col h-[calc(100vh-64px)] lg:h-screen bg-gray-50">
      <header className="p-4 lg:p-8 border-b bg-white">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-green-100 text-green-600 rounded-xl">
            <Bot size={24} />
          </div>
          <div>
            <h1 className="text-xl font-bold">PoliAgent AI</h1>
            <p className="text-xs text-green-600 font-bold flex items-center gap-1">
              <span className="w-2 h-2 bg-green-600 rounded-full animate-pulse"></span>
              Conectado ao Portal da Transparência & Pesquisa Google
            </p>
          </div>
        </div>
      </header>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 lg:p-8 space-y-6">
        {messages.map((m) => (
          <div key={m.id} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] lg:max-w-[70%] p-4 lg:p-6 rounded-3xl ${
              m.role === 'user' 
                ? 'bg-green-600 text-white rounded-tr-none' 
                : 'bg-white border border-gray-100 text-gray-800 shadow-sm rounded-tl-none'
            }`}>
              <div className="flex items-center gap-2 mb-2 opacity-50">
                {m.role === 'user' ? <User size={14} /> : <Bot size={14} />}
                <span className="text-[10px] font-bold uppercase tracking-widest">
                  {m.role === 'user' ? 'Você' : 'PoliAgent'}
                </span>
              </div>
              <div className="whitespace-pre-wrap text-sm lg:text-base leading-relaxed">
                {m.content}
              </div>

              {m.sources && m.sources.length > 0 && (
                <div className="mt-4 pt-4 border-t border-gray-100">
                  <p className="text-[10px] font-bold text-gray-400 mb-2 flex items-center gap-1 uppercase tracking-widest">
                    <Search size={10} /> Fontes verificadas:
                  </p>
                  <div className="flex flex-wrap gap-2">
                    {m.sources.map((s, idx) => (
                      <a 
                        key={idx} 
                        href={s.uri} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="flex items-center gap-1 px-2 py-1 bg-gray-50 text-[10px] text-blue-600 hover:text-blue-800 border rounded-md font-medium transition-colors"
                      >
                        {s.title.slice(0, 30)}... <ExternalLink size={10} />
                      </a>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="bg-white p-4 rounded-3xl border border-gray-100 shadow-sm flex items-center gap-3">
              <Loader2 size={20} className="animate-spin text-green-600" />
              <span className="text-sm text-gray-500 font-medium">Analisando dados e notícias recentes...</span>
            </div>
          </div>
        )}
      </div>

      <div className="p-4 lg:p-8 bg-white border-t">
        <div className="max-w-4xl mx-auto relative">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Pergunte sobre candidatos, gastos parlamentares ou leis..."
            className="w-full pl-6 pr-14 py-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-green-600 text-sm lg:text-base"
          />
          <button
            onClick={handleSend}
            disabled={isLoading || !input.trim()}
            className="absolute right-2 top-1/2 -translate-y-1/2 p-3 bg-green-600 text-white rounded-xl hover:bg-green-700 transition-all disabled:opacity-50 disabled:cursor-not-allowed"
          >
            <Send size={20} />
          </button>
        </div>
        <p className="text-center text-[10px] text-gray-400 mt-4 uppercase tracking-widest font-bold">
          Informações baseadas em dados públicos. Verifique sempre as fontes oficiais.
        </p>
      </div>
    </div>
  );
};

export default Chat;

import React, { useState } from 'react';
import Navigation from './components/Navigation';
import Dashboard from './components/Dashboard';
import Chat from './components/Chat';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard />;
      case 'chat':
        return <Chat />;
      case 'analytics':
        return (
          <div className="flex items-center justify-center h-screen p-8 text-center">
            <div className="max-w-md">
              <h2 className="text-2xl font-bold mb-4">Análise Avançada de Gastos</h2>
              <p className="text-gray-500 mb-6">Estamos processando as planilhas do Portal da Transparência mais recentes (2024). Esta seção estará disponível em breve com detalhamento por parlamentar.</p>
              <button onClick={() => setActiveTab('chat')} className="px-6 py-3 bg-green-600 text-white rounded-xl font-bold">Pergunte ao PoliAgent</button>
            </div>
          </div>
        );
      case 'data':
        return (
          <div className="p-8">
            <h2 className="text-2xl font-bold mb-4">Bases de Dados Integradas</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {[
                { name: 'Portal da Transparência', status: 'Online', records: '2M+', type: 'Federal' },
                { name: 'TSE Eleições (Sessão)', status: 'Online', records: '500k', type: 'Justiça Eleitoral' },
                { name: 'Câmara dos Deputados API', status: 'Syncing', records: '1.2M', type: 'Legislativo' },
              ].map((db, i) => (
                <div key={i} className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm">
                  <div className="flex justify-between items-center mb-4">
                    <span className="text-[10px] font-bold uppercase tracking-widest text-gray-400">{db.type}</span>
                    <span className="flex items-center gap-1 text-[10px] font-bold text-green-600 bg-green-50 px-2 py-0.5 rounded-full">
                      <span className="w-1.5 h-1.5 bg-green-600 rounded-full"></span> {db.status}
                    </span>
                  </div>
                  <h3 className="text-lg font-bold mb-1">{db.name}</h3>
                  <p className="text-sm text-gray-500">{db.records} registros indexados</p>
                </div>
              ))}
            </div>
          </div>
        );
      default:
        return <Dashboard />;
    }
  };

  return (
    <div className="flex flex-col lg:flex-row min-h-screen">
      <Navigation activeTab={activeTab} setActiveTab={setActiveTab} />
      <main className="flex-1 lg:ml-64 pt-16 lg:pt-0 overflow-x-hidden">
        {renderContent()}
      </main>
    </div>
  );
};

export default App;

