import React, { useState, useMemo } from 'react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, AreaChart, Area } from 'recharts';
import { MOCK_METRICS, MOCK_POLLING, MOCK_POLITICIANS } from '../constants';
import { ArrowUpRight, ArrowDownRight, TrendingUp, Users, DollarSign, FileText, Calendar } from 'lucide-react';

const PERIODS = [
  { id: '7d', label: 'Últimos 7 dias' },
  { id: '30d', label: 'Últimos 30 dias' },
  { id: '90d', label: 'Últimos 90 dias' },
  { id: 'ytd', label: 'Ano Atual' },
  { id: 'all', label: 'Todo o Período' },
];

const Dashboard: React.FC = () => {
  const [selectedPeriod, setSelectedPeriod] = useState('all');

  // Simulated data filtering based on period
  const filteredMetrics = useMemo(() => {
    // In a real app, this would fetch data from an API with the period as a parameter.
    // Here we simulate variations to show the UI responding to the filter.
    const multiplier = selectedPeriod === '7d' ? 0.2 : selectedPeriod === '30d' ? 0.5 : selectedPeriod === '90d' ? 0.8 : 1;

    return MOCK_METRICS.map(metric => ({
      ...metric,
      // If it's a cumulative value (currency or number of projects), we scale it down for shorter periods
      value: (metric.type === 'currency' || metric.name.includes('Projetos')) 
        ? metric.value * multiplier 
        : metric.value,
      // Change slightly randomized based on period to simulate reality
      change: metric.change * (0.5 + Math.random())
    }));
  }, [selectedPeriod]);

  const filteredPolling = useMemo(() => {
    if (selectedPeriod === 'all') return MOCK_POLLING;
    if (selectedPeriod === '7d') return MOCK_POLLING.slice(-1);
    if (selectedPeriod === '30d') return MOCK_POLLING.slice(-2);
    return MOCK_POLLING.slice(-3);
  }, [selectedPeriod]);

  return (
    <div className="p-4 lg:p-8 space-y-8">
      <header className="flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div>
          <h1 className="text-3xl font-bold text-gray-900">Visão Geral das Eleições 2026</h1>
          <p className="text-gray-500">Acompanhamento em tempo real de métricas e transparência.</p>
        </div>

        <div className="flex items-center gap-2 bg-white p-1.5 rounded-2xl border border-gray-100 shadow-sm self-start md:self-auto">
          <div className="pl-3 pr-1 text-gray-400">
            <Calendar size={18} />
          </div>
          <select 
            value={selectedPeriod}
            onChange={(e) => setSelectedPeriod(e.target.value)}
            className="bg-transparent border-none focus:ring-0 text-sm font-semibold text-gray-700 pr-8 cursor-pointer"
          >
            {PERIODS.map(period => (
              <option key={period.id} value={period.id}>{period.label}</option>
            ))}
          </select>
        </div>
      </header>

      {/* Metrics Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {filteredMetrics.map((metric, idx) => (
          <div key={idx} className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm hover:shadow-md transition-shadow">
            <div className="flex justify-between items-start mb-4">
              <div className="p-2 bg-gray-50 rounded-xl text-green-600">
                {metric.name.includes('Gasto') ? <DollarSign size={20} /> : 
                 metric.name.includes('Eleitores') ? <Users size={20} /> :
                 metric.name.includes('Projetos') ? <FileText size={20} /> : <TrendingUp size={20} />}
              </div>
              <div className={`flex items-center text-xs font-bold px-2 py-1 rounded-full ${metric.change >= 0 ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'}`}>
                {metric.change >= 0 ? <ArrowUpRight size={14} className="mr-1" /> : <ArrowDownRight size={14} className="mr-1" />}
                {Math.abs(metric.change).toFixed(1)}%
              </div>
            </div>
            <p className="text-sm font-medium text-gray-500 mb-1">{metric.name}</p>
            <h3 className="text-2xl font-bold">
              {metric.type === 'currency' ? `R$ ${(metric.value / 1e9).toFixed(2)}B` : 
               metric.type === 'percentage' ? `${metric.value.toFixed(1)}%` : 
               Math.floor(metric.value).toLocaleString('pt-BR')}
            </h3>
          </div>
        ))}
      </div>

      {/* Charts Section */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm">
          <div className="flex justify-between items-center mb-6">
            <h3 className="text-lg font-bold">Simulação de Intenção de Voto</h3>
            <span className="text-xs bg-gray-100 px-2 py-1 rounded-md text-gray-500 font-medium italic">
              Exibindo {PERIODS.find(p => p.id === selectedPeriod)?.label.toLowerCase()}
            </span>
          </div>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={filteredPolling}>
                <defs>
                  <linearGradient id="colorA" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#004b23" stopOpacity={0.1}/>
                    <stop offset="95%" stopColor="#004b23" stopOpacity={0}/>
                  </linearGradient>
                  <linearGradient id="colorB" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#002776" stopOpacity={0.1}/>
                    <stop offset="95%" stopColor="#002776" stopOpacity={0}/>
                  </linearGradient>
                  <linearGradient id="colorC" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#eab308" stopOpacity={0.1}/>
                    <stop offset="95%" stopColor="#eab308" stopOpacity={0}/>
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" />
                <XAxis dataKey="date" stroke="#94a3b8" fontSize={12} tickLine={false} axisLine={false} />
                <YAxis stroke="#94a3b8" fontSize={12} tickLine={false} axisLine={false} unit="%" />
                <Tooltip 
                  contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)' }}
                />
                <Area type="monotone" dataKey="candidateA" name="Cenário Direita" stroke="#004b23" fillOpacity={1} fill="url(#colorA)" strokeWidth={3} />
                <Area type="monotone" dataKey="candidateB" name="Cenário Esquerda" stroke="#002776" fillOpacity={1} fill="url(#colorB)" strokeWidth={3} />
                <Area type="monotone" dataKey="candidateC" name="Terceira Via" stroke="#eab308" fillOpacity={1} fill="url(#colorC)" strokeWidth={3} />
              </AreaChart>
