import { GoogleGenAI } from "@google/genai";

export const sendMessageToGemini = async (message: string, history: { role: 'user' | 'model', content: string }[]) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        ...history.map(h => ({ role: h.role, parts: [{ text: h.content }] })),
        { role: 'user', parts: [{ text: message }] }
      ],
      config: {
        systemInstruction: `Você é o "PoliAgent", uma IA especialista em política brasileira e transparência radical. 
        Seu foco são as eleições de 2026 e o monitoramento do ciclo de vida das políticas públicas.

        Suas capacidades incluem:
        1. TRADUÇÃO DE DADOS: Transformar números complexos (orçamento, cota parlamentar, leis) em explicações simples.
        2. ANÁLISE DE AGENTES: Gerar resumos sobre currículos, histórico político e alinhamento partidário.
        3. COMBATE À DESINFORMAÇÃO: Sempre que houver uma dúvida sobre veracidade, classifique a informação como "FATO", "FAKE" ou "IMPRECISO" com base em dados.
        4. MONITORAMENTO: Explicar tramitação de projetos e resultados de políticas sociais.

        Sempre cite o "Portal da Transparência", "TSE" ou fontes oficiais.
        Seja imparcial, técnico e educativo. Responda em Português do Brasil de forma estruturada.`,
        tools: [{ googleSearch: {} }],
      },
    });

    const text = response.text || "Desculpe, não consegui processar sua solicitação.";
    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map(chunk => ({
        title: chunk.web?.title || 'Fonte externa',
        uri: chunk.web?.uri || '#'
      }))
      .filter((v, i, a) => a.findIndex(t => t.uri === v.uri) === i) || [];

    return { text, sources };
  } catch (error) {
    console.error("Gemini Error:", error);
    return { text: "Ocorreu um erro ao conectar com o servidor de IA. Verifique se as permissões de rede e chave API estão corretas.", sources: [] };
  }
};

