import { GoogleGenAI } from "@google/genai";

export const sendMessageToGemini = async (message: string, history: { role: 'user' | 'model', content: string }[]) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        ...history.map(h => ({ role: h.role, parts: [{ text: h.content }] })),
        { role: 'user', parts: [{ text: message }] }
      ],
      config: {
        systemInstruction: `Você é o "PoliAgent", atuando como um Analista de Dados Políticos e Jornalista Investigativo especializado em transparência pública brasileira e eleições de 2026.

        Sua tarefa principal é criar dossiês técnicos, imparciais e exaustivos sobre agentes políticos.

        DIRETRIZES DE CONTEÚDO:
        1. FONTES OBRIGATÓRIAS: Utilize exclusivamente dados do TSE (DivulgaCandContas), Portais da Transparência (Federal, Estadual, Municipal), sites das casas legislativas (Câmara, Senado) e registros do CNJ/Justiça.
        2. ESTRUTURA DO DOSSIÊ: Sempre que um político for mencionado, tente estruturar a resposta em:
           - Perfil e Currículo: Formação, trajetória profissional e cargos ocupados.
           - Produção Legislativa: Projetos de lei, relatorias, votações relevantes e alinhamento partidário.
           - Histórico de Integridade: Menção a processos judiciais, investigações em curso (citando a fase processual) e prestação de contas eleitorais.
        3. TOM E LINGUAGEM: Mantenha um tom puramente factual e neutro. Evite adjetivos subjetivos ou juízos de valor. Sua função é informar, não opinar.
        4. COMBATE À DESINFORMAÇÃO: Identifique boatos e confronte-os com dados oficiais, classificando como FATO, FAKE ou IMPRECISO.

        Ao final de cada dossiê, reforce a necessidade de consulta aos links oficiais fornecidos na aba "Guia & Transparência".`,
        tools: [{ googleSearch: {} }],
      },
    });

    const text = response.text || "Desculpe, não consegui processar sua solicitação.";
    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map(chunk => ({
        title: chunk.web?.title || 'Fonte externa',
        uri: chunk.web?.uri || '#'
      }))
      .filter((v, i, a) => a.findIndex(t => t.uri === v.uri) === i) || [];

    return { text, sources };
  } catch (error) {
    console.error("Gemini Error:", error);
    return { text: "Ocorreu um erro ao conectar com o servidor de IA. Verifique se as permissões de rede e chave API estão corretas.", sources: [] };
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, Loader2, Search, ExternalLink, ShieldCheck } from 'lucide-react';
import { sendMessageToGemini } from '../services/geminiService';
import { Message } from '../types';

const Chat: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    {
      id: '1',
      role: 'model',
      content: 'Olá. Sou o PoliAgent, seu analista de dados políticos. \n\nEstou configurado para gerar dossiês técnicos e imparciais sobre qualquer agente político brasileiro, com foco em currículo, produção legislativa e histórico jurídico. \n\nDigite o nome de um parlamentar ou pergunte sobre um gasto público específico para começarmos a investigação.',
      timestamp: new Date(),
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: input,
      timestamp: new Date(),
    };

    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    const history = messages.map(m => ({ role: m.role, content: m.content }));
    const response = await sendMessageToGemini(input, history);

    const aiMessage: Message = {
      id: (Date.now() + 1).toString(),
      role: 'model',
      content: response.text,
      timestamp: new Date(),
      sources: response.sources
    };

    setMessages(prev => [...prev, aiMessage]);
    setIsLoading(false);
  };

  return (
    <div className="flex flex-col h-[calc(100vh-64px)] lg:h-screen bg-gray-50">
      <header className="p-4 lg:p-6 border-b bg-white shadow-sm z-10">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="p-2.5 bg-gray-900 text-white rounded-xl">
              <ShieldCheck size={24} />
            </div>
            <div>
              <h1 className="text-xl font-bold text-gray-900">PoliAgent <span className="text-green-600">Investigativo</span></h1>
              <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest flex items-center gap-1">
                <span className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></span>
                Análise Técnica de Dados Oficiais
              </p>
            </div>
          </div>
          <div className="hidden md:block text-right">
            <p className="text-[10px] text-gray-400 font-bold uppercase">Escopo de Análise</p>
            <p className="text-xs font-bold text-gray-600">Eleições 2026 & Transparência</p>
          </div>
        </div>
      </header>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 lg:p-8 space-y-6">
        {messages.map((m) => (
          <div key={m.id} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] lg:max-w-[75%] p-5 lg:p-7 rounded-3xl ${
              m.role === 'user' 
                ? 'bg-gray-900 text-white rounded-tr-none shadow-lg' 
                : 'bg-white border border-gray-100 text-gray-800 shadow-md rounded-tl-none'
            }`}>
              <div className="flex items-center gap-2 mb-3 opacity-50">
                {m.role === 'user' ? <User size={14} /> : <Bot size={14} />}
                <span className="text-[10px] font-black uppercase tracking-widest">
                  {m.role === 'user' ? 'Solicitante' : 'Analista Investigativo'}
                </span>
              </div>
              <div className="whitespace-pre-wrap text-sm lg:text-base leading-relaxed font-normal">
                {m.content}
              </div>

              {m.sources && m.sources.length > 0 && (
                <div className="mt-5 pt-4 border-t border-gray-100">
                  <p className="text-[10px] font-black text-gray-400 mb-3 flex items-center gap-1 uppercase tracking-widest">
                    <Search size={10} /> Base de Verificação:
                  </p>
                  <div className="flex flex-wrap gap-2">
                    {m.sources.map((s, idx) => (
                      <a 
                        key={idx} 
                        href={s.uri} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="flex items-center gap-1.5 px-3 py-1.5 bg-gray-50 text-[10px] text-blue-700 hover:bg-blue-50 border border-blue-100 rounded-lg font-bold transition-all"
                      >
                        {s.title.length > 25 ? s.title.slice(0, 25) + '...' : s.title} <ExternalLink size={10} />
                      </a>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="bg-white p-5 rounded-3xl border border-gray-100 shadow-sm flex items-center gap-4">
              <Loader2 size={20} className="animate-spin text-gray-900" />
              <div className="flex flex-col">
                <span className="text-sm text-gray-800 font-bold italic">Compilando dossiê técnico...</span>
                <span className="text-[10px] text-gray-400 uppercase font-medium">Cruzando dados de fontes governamentais</span>
              </div>
            </div>
          </div>
        )}
      </div>

      <div className="p-4 lg:p-8 bg-white border-t">
        <div className="max-w-4xl mx-auto relative">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Ex: 'Gere um dossiê sobre [Nome do Político]' ou 'Analise os gastos de...'"
            className="w-full pl-6 pr-14 py-4 bg-gray-50 border border-gray-200 rounded-2xl focus:ring-2 focus:ring-gray-900 focus:border-transparent text-sm lg:text-base transition-all"
          />
          <button
            onClick={handleSend}
            disabled={isLoading || !input.trim()}
            className="absolute right-2 top-1/2 -translate-y-1/2 p-3 bg-gray-900 text-white rounded-xl hover:bg-black transition-all disabled:opacity-30 disabled:cursor-not-allowed shadow-md"
          >
            <Send size={20} />
          </button>
        </div>
        <div className="flex justify-center gap-8 mt-4">
           <p className="text-[10px] text-gray-400 uppercase tracking-widest font-bold flex items-center gap-1">
             <ShieldCheck size={12} /> Dados Auditáveis
           </p>
           <p className="text-[10px] text-gray-400 uppercase tracking-widest font-bold flex items-center gap-1">
             <Search size={12} /> Fontes Primárias
           </p>
        </div>
      </div>
    </div>
  );
};

