import { GoogleGenAI } from "@google/genai";

export const sendMessageToGemini = async (message: string, history: { role: 'user' | 'model', content: string }[]) => {
  // Initialize AI client with API key from environment variable
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    // Using gemini-3-pro-preview for complex technical and political reasoning tasks
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: [
        ...history.map(h => ({ role: h.role, parts: [{ text: h.content }] })),
        { role: 'user', parts: [{ text: message }] }
      ],
      config: {
        systemInstruction: `Você é o "PoliAgent", atuando como um Analista de Dados Políticos e Jornalista Investigativo especializado em transparência pública brasileira e eleições de 2026.

        Sua tarefa principal é criar dossiês técnicos, imparciais e exaustivos sobre agentes políticos.

        DIRETRIZES DE CONTEÚDO:
        1. FONTES OBRIGATÓRIAS: Utilize exclusivamente dados do TSE (DivulgaCandContas), Portais da Transparência (Federal, Estadual, Municipal), sites das casas legislativas (Câmara, Senado) e registros do CNJ/Justiça.
        2. ESTRUTURA DO DOSSIÊ: Sempre que um político for mencionado, tente estruturar a resposta em:
           - Perfil e Currículo: Formação, trajetória profissional e cargos ocupados.
           - Produção Legislativa: Projetos de lei, relatorias, votações relevantes e alinhamento partidário.
           - Histórico de Integridade: Menção a processos judiciais, investigações em curso (citando a fase processual) e prestação de contas eleitorais.
        3. TOM E LINGUAGEM: Mantenha um tom puramente factual e neutro. Evite adjetivos subjetivos ou juízos de valor. Sua função é informar, não opinar.
        4. COMBATE À DESINFORMAÇÃO: Identifique boatos e confronte-os com dados oficiais, classificando como FATO, FAKE ou IMPRECISO.

        Ao final de cada dossiê, reforce a necessidade de consulta aos links oficiais fornecidos na aba "Guia & Transparência".`,
        tools: [{ googleSearch: {} }],
      },
    });

    // Extract text output from GenerateContentResponse using the .text property
    const text = response.text || "Desculpe, não consegui processar sua solicitação.";

    // Extract website URLs from groundingChunks for source transparency
    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map(chunk => ({
        title: chunk.web?.title || 'Fonte externa',
        uri: chunk.web?.uri || '#'
      }))
      .filter((v, i, a) => a.findIndex(t => t.uri === v.uri) === i) || [];

    return { text, sources };
  } catch (error) {
    console.error("Gemini Error:", error);
    return { text: "Ocorreu um erro ao conectar com o servidor de IA. Verifique se as permissões de rede e chave API estão corretas.", sources: [] };
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, Loader2, X, MessageCircle, ShieldCheck, Maximize2, Minimize2 } from 'lucide-react';
import { sendMessageToGemini } from '../services/geminiService';
import { Message } from '../types';

interface GlobalChatProps {
  currentContext: string;
}

const GlobalChat: React.FC<GlobalChatProps> = ({ currentContext }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [isMinimized, setIsMinimized] = useState(false);
  const [messages, setMessages] = useState<Message[]>([
    {
      id: 'welcome',
      role: 'model',
      content: `Olá! Sou seu assistente de transparência. Notei que você está em: **${currentContext}**. Como posso ajudar com os dados desta seção?`,
      timestamp: new Date(),
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading, isOpen]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: input,
      timestamp: new Date(),
    };

    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    const history = messages.map(m => ({ role: m.role, content: m.content }));
    // Injetando contexto na mensagem para a IA
    const contextualPrompt = `[Contexto Atual: ${currentContext}] ${input}`;
    const response = await sendMessageToGemini(contextualPrompt, history);

    const aiMessage: Message = {
      id: (Date.now() + 1).toString(),
      role: 'model',
      content: response.text,
      timestamp: new Date(),
      sources: response.sources
    };

    setMessages(prev => [...prev, aiMessage]);
    setIsLoading(false);
  };

  return (
    <>
      {/* Floating Action Button */}
      {!isOpen && (
        <button
          onClick={() => setIsOpen(true)}
          className="fixed bottom-6 right-6 w-16 h-16 bg-green-600 text-white rounded-full shadow-2xl flex items-center justify-center hover:scale-110 active:scale-95 transition-all z-[100] group"
        >
          <div className="absolute inset-0 bg-green-600 rounded-full animate-ping opacity-20 group-hover:hidden"></div>
          <MessageCircle size={28} />
          <span className="absolute -top-2 -right-2 bg-red-500 text-white text-[10px] font-bold px-2 py-1 rounded-full border-2 border-white">IA</span>
        </button>
      )}

      {/* Chat Window */}
      {isOpen && (
        <div className={`fixed bottom-6 right-6 w-[90vw] md:w-[400px] ${isMinimized ? 'h-16' : 'h-[600px] max-h-[80vh]'} bg-white border border-gray-200 shadow-2xl rounded-3xl overflow-hidden flex flex-col transition-all z-[100] glass`}>
          {/* Header */}
          <header className="p-4 bg-gray-900 text-white flex items-center justify-between">
            <div className="flex items-center gap-2">
              <Bot size={20} className="text-green-400" />
              <div>
                <h3 className="text-sm font-bold">PoliAgent Global</h3>
                <p className="text-[9px] text-gray-400 uppercase tracking-widest font-black">Consultoria em Tempo Real</p>
              </div>
            </div>
            <div className="flex items-center gap-2">
              <button onClick={() => setIsMinimized(!isMinimized)} className="p-1 hover:bg-white/10 rounded transition-colors">
                {isMinimized ? <Maximize2 size={16} /> : <Minimize2 size={16} />}
              </button>
              <button onClick={() => setIsOpen(false)} className="p-1 hover:bg-white/10 rounded transition-colors">
                <X size={16} />
              </button>
            </div>
          </header>

          {!isMinimized && (
            <>
              {/* Messages Area */}
              <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50/50">
                {messages.map((m) => (
                  <div key={m.id} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                    <div className={`max-w-[85%] p-3 rounded-2xl text-sm ${
                      m.role === 'user' 
                        ? 'bg-green-600 text-white rounded-tr-none shadow-md' 
                        : 'bg-white border border-gray-100 text-gray-800 shadow-sm rounded-tl-none'
                    }`}>
                      <div className="whitespace-pre-wrap leading-relaxed">
                        {m.content}
                      </div>
                      {m.sources && m.sources.length > 0 && (
                        <div className="mt-2 pt-2 border-t border-gray-100 flex flex-wrap gap-1">
                          {m.sources.slice(0, 2).map((s, idx) => (
                            <a key={idx} href={s.uri} target="_blank" rel="noopener noreferrer" className="text-[9px] font-bold text-blue-600 underline">
                              {s.title.slice(0, 15)}...
                            </a>
                          ))}
                        </div>
                      )}
                    </div>
                  </div>
                ))}
                {isLoading && (
                  <div className="flex justify-start">
                    <div className="bg-white p-3 rounded-2xl shadow-sm flex items-center gap-2 border border-gray-100">
                      <Loader2 size={14} className="animate-spin text-green-600" />
                      <span className="text-[10px] font-bold text-gray-400 uppercase italic">Analisando dados oficiais...</span>
                    </div>
                  </div>
                )}
              </div>

              {/* Input Area */}
              <div className="p-4 border-t bg-white">
                <div className="relative">
                  <input
                    type="text"
                    value={input}
                    onChange={(e) => setInput(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                    placeholder="Pergunte sobre os dados..."
                    className="w-full pl-4 pr-10 py-3 bg-gray-100 border-none rounded-xl text-xs focus:ring-2 focus:ring-green-600 transition-all"
                  />
                  <button
                    onClick={handleSend}
                    disabled={isLoading || !input.trim()}
                    className="absolute right-1 top-1/2 -translate-y-1/2 p-2 text-green-600 hover:text-green-700 disabled:opacity-30"
                  >
                    <Send size={18} />
                  </button>
                </div>
                <div className="flex justify-between items-center mt-2 px-1">
                  <span className="text-[9px] text-gray-400 font-bold flex items-center gap-1">
                    <ShieldCheck size={10} /> DADOS CRIPTOGRAFADOS
                  </span>
                  <span className="text-[9px] text-gray-400 font-bold">API GEMINI 3 PRO</span>
                </div>
              </div>
            </>
          )}
        </div>
      )}
    </>
  );
};

export default GlobalChat;

