import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, Loader2, Search, ExternalLink, ShieldCheck } from 'lucide-react';
import { sendMessageToGemini } from '../services/geminiService';
import { Message } from '../types';

interface ChatProps {
  initialQuery?: string | null;
  onClearQuery?: () => void;
}

const Chat: React.FC<ChatProps> = ({ initialQuery, onClearQuery }) => {
  const [messages, setMessages] = useState<Message[]>([
    {
      id: '1',
      role: 'model',
      content: 'Olá. Sou o PoliAgent, seu analista de dados políticos. \n\nEstou configurado para gerar dossiês técnicos e imparciais sobre qualquer agente político brasileiro, com foco em currículo, produção legislativa e histórico jurídico. \n\nDigite o nome de um parlamentar ou pergunte sobre um gasto público específico para começarmos a investigação.',
      timestamp: new Date(),
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  // Efeito para tratar buscas vindas de outras abas (Ex: NewsConsultory)
  useEffect(() => {
    if (initialQuery && !isLoading) {
      handleSend(initialQuery);
      if (onClearQuery) onClearQuery();
    }
  }, [initialQuery]);

  const handleSend = async (queryOverride?: string) => {
    const textToSend = queryOverride || input;
    if (!textToSend.trim() || isLoading) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: textToSend,
      timestamp: new Date(),
    };

    setMessages(prev => [...prev, userMessage]);
    if (!queryOverride) setInput('');
    setIsLoading(true);

    const history = messages.map(m => ({ role: m.role, content: m.content }));
    const response = await sendMessageToGemini(textToSend, history);

    const aiMessage: Message = {
      id: (Date.now() + 1).toString(),
      role: 'model',
      content: response.text,
      timestamp: new Date(),
      sources: response.sources
    };

    setMessages(prev => [...prev, aiMessage]);
    setIsLoading(false);
  };

  return (
    <div className="flex flex-col h-[calc(100vh-64px)] lg:h-screen bg-gray-50">
      <header className="p-4 lg:p-6 border-b bg-white shadow-sm z-10">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="p-2.5 bg-gray-900 text-white rounded-xl">
              <ShieldCheck size={24} />
            </div>
            <div>
              <h1 className="text-xl font-bold text-gray-900">PoliAgent <span className="text-green-600">Investigativo</span></h1>
              <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest flex items-center gap-1">
                <span className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></span>
                Análise Técnica de Dados Oficiais
              </p>
            </div>
          </div>
