import React, { useState, useMemo } from 'react';
import { MOCK_NEWS, MOCK_POLITICIANS } from '../constants';
import { Search, ShieldCheck, ShieldAlert, BarChart3, ExternalLink, Calendar, Newspaper, TrendingUp, TrendingDown, Minus, Bot, Loader2 } from 'lucide-react';

interface NewsConsultoryProps {
  onSearchIA?: (query: string) => void;
}

const NewsConsultory: React.FC<NewsConsultoryProps> = ({ onSearchIA }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCandidate, setSelectedCandidate] = useState<string | 'all'>('all');

  // Função robusta de normalização
  const normalize = (text: string) => 
    text ? text.normalize("NFD").replace(/[\u0300-\u036f]/g, "").toLowerCase().trim() : "";

  const filteredNews = useMemo(() => {
    const normalizedSearch = normalize(searchTerm);

    // Se a busca estiver vazia e não houver filtro de chip, retorna tudo
    if (!normalizedSearch && selectedCandidate === 'all') return MOCK_NEWS;

    // Encontra políticos que combinam com o nome buscado
    const matchingPoliticianIds = MOCK_POLITICIANS
      .filter(p => normalize(p.name).includes(normalizedSearch))
      .map(p => p.id);

    return MOCK_NEWS.filter(article => {
      const normalizedTitle = normalize(article.title);
      const normalizedSummary = normalize(article.summary);

      // Busca combina se: está no título, no resumo OU se o ID do candidato da notícia bate com o nome buscado
      const matchesSearch = normalizedTitle.includes(normalizedSearch) || 
                          normalizedSummary.includes(normalizedSearch) ||
                          matchingPoliticianIds.includes(article.candidateId);

      const matchesCandidate = selectedCandidate === 'all' || article.candidateId === selectedCandidate;

      return matchesSearch && matchesCandidate;
    });
  }, [searchTerm, selectedCandidate]);

  const getSentimentIcon = (sentiment: string) => {
    switch (sentiment) {
      case 'positivo': return <TrendingUp size={16} className="text-green-500" />;
      case 'negativo': return <TrendingDown size={16} className="text-red-500" />;
      default: return <Minus size={16} className="text-gray-400" />;
    }
  };

  const getStatusBadge = (status: string) => {
    switch (status) {
      case 'verificado': 
        return <span className="flex items-center gap-1 text-[10px] font-bold text-green-600 bg-green-50 px-2 py-0.5 rounded-full"><ShieldCheck size={12}/> FATO</span>;
      case 'alerta': 
        return <span className="flex items-center gap-1 text-[10px] font-bold text-red-600 bg-red-50 px-2 py-0.5 rounded-full"><ShieldAlert size={12}/> ALERTA</span>;
      default: 
        return <span className="flex items-center gap-1 text-[10px] font-bold text-gray-500 bg-gray-50 px-2 py-0.5 rounded-full">EM ANÁLISE</span>;
    }
  };

  const handleIASearchTrigger = () => {
    if (onSearchIA) {
      const query = searchTerm.trim() || "Sóstenes Cavalcante";
      onSearchIA(`PoliAgent, busque notícias recentes e verifique fatos sobre o parlamentar ${query}. Foque em atividades legislativas e declarações recentes de 2024.`);
    }
  };

  return (
    <div className="p-4 lg:p-8 space-y-8 max-w-6xl mx-auto pb-24">
      <header className="flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div className="space-y-2">
          <div className="inline-flex items-center gap-2 px-3 py-1 bg-blue-50 text-blue-700 rounded-full text-[10px] font-black uppercase tracking-widest">
            <Newspaper size={14} /> Agregação de Mídia Independente
          </div>
          <h1 className="text-3xl font-extrabold text-gray-900 tracking-tight">Consultório de Notícias</h1>
          <p className="text-gray-500 italic">Analise a cobertura mediática e o sentimento das manchetes em tempo real.</p>
        </div>

        <div className="flex flex-1 max-w-md relative group">
          <div className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-blue-500 transition-colors">
            {searchTerm && filteredNews.length > 0 ? <Loader2 size={18} className="animate-spin" /> : <Search size={18} />}
          </div>
          <input 
            type="text" 
            placeholder="Buscar por candidato ou manchete..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full pl-12 pr-4 py-3.5 bg-white border border-gray-200 rounded-full focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 shadow-sm hover:shadow-md transition-all outline-none text-gray-700 placeholder:text-gray-400 font-medium"
          />
        </div>
      </header>

      {/* Chips de Filtro Rápido */}
      <section className="flex items-center gap-4 overflow-x-auto pb-4 no-scrollbar">
        <button 
          onClick={() => setSelectedCandidate('all')}
          className={`px-6 py-2 rounded-full text-xs font-black uppercase tracking-wider transition-all flex-shrink-0 border-2 ${
            selectedCandidate === 'all' && !searchTerm ? 'bg-gray-900 text-white border-gray-900 shadow-lg' : 'bg-white text-gray-400 border-gray-100 hover:border-gray-200'
          }`}
        >
          Ver Todas
        </button>
        {MOCK_POLITICIANS.map(pol => (
          <button 
            key={pol.id}
            onClick={() => {
                setSelectedCandidate(pol.id);
                setSearchTerm(''); // Limpa busca manual ao clicar no chip
            }}
            className={`px-5 py-2 rounded-full text-xs font-bold transition-all flex-shrink-0 flex items-center gap-2 border-2 ${
              selectedCandidate === pol.id ? 'bg-blue-600 text-white border-blue-600 shadow-lg shadow-blue-200' : 'bg-white text-gray-500 border-gray-100 hover:border-blue-200'
            }`}
          >
            <div className={`w-5 h-5 rounded-full flex items-center justify-center text-[10px] font-black ${selectedCandidate === pol.id ? 'bg-white text-blue-600' : 'bg-gray-100 text-gray-500'}`}>
              {pol.name.charAt(0)}
            </div>
            {pol.name}
          </button>
        ))}
      </section>

      {/* Grid de Conteúdo */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredNews.length > 0 ? filteredNews.map((article) => (
          <article key={article.id} className="bg-white rounded-[2.5rem] border border-gray-100 shadow-sm hover:shadow-2xl hover:-translate-y-1 transition-all overflow-hidden flex flex-col group">
