              <div className="flex justify-between items-start">
                <div className="flex flex-col gap-0.5">
                  <span className="text-[10px] font-black text-blue-600 uppercase tracking-widest">{article.source}</span>
                  <span className="text-[10px] text-gray-400 font-bold flex items-center gap-1">
                    <Calendar size={10} /> {article.date}
                  </span>
                </div>
                {getStatusBadge(article.factCheckStatus)}
              </div>

              <h3 className="text-[17px] font-bold text-gray-900 leading-snug group-hover:text-blue-700 transition-colors">
                {article.title}
              </h3>

              <p className="text-sm text-gray-500 line-clamp-3 leading-relaxed">
                {article.summary}
              </p>

              <div className="pt-4 border-t border-gray-50 flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <span className="text-[9px] font-black text-gray-300 uppercase tracking-tighter">Viés da Mídia</span>
                  <div className="p-1.5 bg-gray-50 rounded-xl">
                    {getSentimentIcon(article.sentiment)}
                  </div>
                </div>

                <a 
                  href={article.url} 
                  target="_blank" 
                  rel="noopener noreferrer"
                  className="p-2.5 bg-gray-50 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded-xl transition-all"
                >
                  <ExternalLink size={18} />
                </a>
              </div>
            </div>

            <button className="w-full bg-gray-50/50 py-4 text-[10px] font-black uppercase tracking-widest text-gray-500 hover:bg-blue-600 hover:text-white transition-all flex items-center justify-center gap-2 border-t border-gray-100">
              <BarChart3 size={14} /> Fact-Check Investigativo
            </button>
          </article>
        )) : (
          <div className="col-span-full py-16 text-center">
            <div className="max-w-md mx-auto bg-white p-10 rounded-[3rem] border border-dashed border-gray-200 shadow-sm">
                <div className="w-20 h-20 bg-gray-50 rounded-full flex items-center justify-center mx-auto text-gray-300 mb-6">
                  <Search size={40} />
                </div>
                <h3 className="text-xl font-bold text-gray-900 mb-2">Sem resultados locais</h3>
                <p className="text-gray-500 text-sm mb-8 leading-relaxed">
                    Não encontramos manchetes arquivadas para <strong>"{searchTerm}"</strong>. 
                    Nossa base local é atualizada diariamente, mas alguns parlamentares podem estar fora do radar recente.
                </p>

                <div className="bg-blue-600 p-8 rounded-[2rem] text-white shadow-2xl shadow-blue-300/50">
                    <Bot size={32} className="mx-auto mb-4" />
                    <p className="font-bold text-lg mb-4 leading-tight">Deseja que o PoliAgent busque agora na internet?</p>
                    <button 
                        onClick={handleIASearchTrigger}
                        className="w-full bg-white text-blue-700 px-6 py-4 rounded-2xl font-black uppercase tracking-widest text-xs hover:bg-blue-50 hover:scale-[1.02] active:scale-95 transition-all shadow-lg"
                    >
                        Buscar com IA na Web
                    </button>
                </div>
            </div>
          </div>
        )}
      </div>

      {/* Widget de Insights */}
      <section className="bg-gradient-to-br from-gray-900 to-blue-950 rounded-[3rem] p-10 text-white shadow-2xl relative overflow-hidden">
        <div className="relative z-10 flex flex-col lg:flex-row items-center gap-12">
          <div className="flex-1 space-y-6">
            <h2 className="text-3xl font-bold leading-tight">Monitor de Viés Algorítmico</h2>
            <p className="text-gray-400 text-base leading-relaxed max-w-xl">
              Nossa IA analisa mais de 500 portais de notícias por hora para detectar padrões de <strong>linguagem tendenciosa</strong> ou <strong>omissão seletiva</strong> em manchetes políticas.
            </p>
            <div className="flex flex-wrap gap-4 pt-4">
              <div className="bg-white/5 backdrop-blur-md border border-white/10 p-5 rounded-3xl flex-1 min-w-[120px] text-center">
                <p className="text-3xl font-black text-green-400">12%</p>
                <p className="text-[9px] text-gray-500 font-black uppercase tracking-[0.2em] mt-1">Favoráveis</p>
