import React, { useState } from 'react';
import Navigation from './components/Navigation';
import Chat from './components/Chat';
import Guide from './components/Guide';
import VoterManual from './components/VoterManual';
import GlobalChat from './components/GlobalChat';
import { DATA_CATEGORIES } from './constants';
import * as LucideIcons from 'lucide-react';
import { ExternalLink } from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('manual');
  const [pendingSearch, setPendingSearch] = useState<string | null>(null);

  const getContextLabel = () => {
    switch(activeTab) {
      case 'manual': return 'Manual do Eleitor';
      case 'chat': return 'PoliAgent AI (Dossiês)';
      case 'data': return 'Base de Dados Integrada';
      case 'guide': return 'Guia de Transparência';
      default: return 'Portal Eleições 2026';
    }
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'chat':
        return <Chat initialQuery={pendingSearch} onClearQuery={() => setPendingSearch(null)} />;
      case 'guide':
        return <Guide onGoToChat={() => setActiveTab('chat')} />;
      case 'manual':
        return <VoterManual />;
      case 'data':
        return (
          <div className="p-4 lg:p-8 space-y-8">
            <header>
              <h1 className="text-3xl font-bold text-gray-900">Base de Dados Integrada</h1>
              <p className="text-gray-500">Dados abertos estruturados para transparência e engajamento cidadão.</p>
            </header>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
              {DATA_CATEGORIES.map((cat) => {
                // @ts-ignore - dynamic icon access
                const Icon = LucideIcons[cat.icon] || LucideIcons.Database;
                return (
                  <a 
                    key={cat.id} 
                    href={cat.url}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm hover:shadow-xl hover:border-green-200 transition-all cursor-pointer group flex flex-col justify-between"
                  >
                    <div>
                      <div className="w-12 h-12 bg-gray-50 text-green-600 rounded-2xl flex items-center justify-center mb-4 group-hover:bg-green-600 group-hover:text-white transition-colors">
                        <Icon size={24} />
                      </div>
                      <h3 className="text-lg font-bold mb-2 text-gray-900 group-hover:text-green-700">{cat.title}</h3>
                      <p className="text-sm text-gray-500 leading-relaxed">{cat.desc}</p>
                    </div>

                    <div className="mt-6 flex items-center justify-between">
                      <span className="text-[10px] font-bold text-green-600 uppercase tracking-widest bg-green-50 px-2 py-1 rounded">Online</span>
                      <div className="flex items-center gap-1 text-xs font-bold text-gray-400 group-hover:text-green-600 transition-colors">
                        Acessar base <ExternalLink size={14} />
                      </div>
                    </div>
                  </a>
                );
              })}
            </div>

            <div className="bg-white p-8 rounded-3xl border border-gray-100 text-center">
              <h3 className="text-xl font-bold mb-2">Tradução e Acesso</h3>
              <p className="text-gray-500 mb-6 max-w-2xl mx-auto">Nossa plataforma não apenas fornece os dados, mas os traduz em relatórios compreensíveis. Use o PoliAgent para gerar análises customizadas a partir destes dados.</p>
              <div className="flex flex-wrap justify-center gap-4">
                <div className="px-4 py-2 bg-gray-50 rounded-full text-xs font-bold text-gray-600">CSV estruturado</div>
                <div className="px-4 py-2 bg-gray-50 rounded-full text-xs font-bold text-gray-600">API REST integrada</div>
                <div className="px-4 py-2 bg-gray-50 rounded-full text-xs font-bold text-gray-600">Dashboards interativos</div>
              </div>
            </div>
          </div>
        );
      default:
        return <Chat />;
    }
  };

  return (
    <div className="flex flex-col lg:flex-row min-h-screen">
      <Navigation activeTab={activeTab} setActiveTab={setActiveTab} />
      <main className="flex-1 lg:ml-64 pt-16 lg:pt-0 overflow-x-hidden bg-gray-50">
        {renderContent()}
      </main>

      {/* Camada de IA Ubíqua */}
      <GlobalChat currentContext={getContextLabel()} />
    </div>
  );
};

export default App;
